import { NextResponse, type NextRequest } from 'next/server';

/**
 * middleware.ts — Passthrough de parámetros de debug (Next 16 standard).
 * Requiere capturar searchParams y pasarlos como headers para que
 * los Layouts (Server Components) puedan verlos.
 */
export function middleware(request: NextRequest) {
    const debugAuth = request.nextUrl.searchParams.get('debugAuth');
    const requestHeaders = new Headers(request.headers);
    
    // Pasamos el pathname para que los Layouts puedan decidir redirecciones
    requestHeaders.set('x-pathname', request.nextUrl.pathname);

    if (debugAuth) {
        requestHeaders.set('x-debug-auth', debugAuth);
    }

    return NextResponse.next({
        request: {
            headers: requestHeaders,
        },
    });
}

export const config = {
    matcher: [
        '/((?!api|_next/static|_next/image|favicon.ico).*)',
    ],
};
